  "login.stateHint": { en: "Unlocks State-specific welfare schemes.", hi: "राज्य-विशिष्ट कल्याण योजनाएँ अनलॉक करता है।", mr: "राज्य-विशिष्ट कल्याण योजना अनलॉक करते.", ta: "மாநில-குறிப்பிட்ட நலத்திட்டங்களைத் திறக்கிறது.", bn: "রাজ্য-নির্দিষ্ট কল্যাণ প্রকল্প আনলক করে।" },
